  it('should emit drain event when write queue is empty', (done) => {
    const dirty = new Dirty('test.db');
    dirty.on('drain', () => {
      done();
    });
    dirty.set('key', 'value', () => {
      dirty.set('key', undefined, () => {
        dirty.set('key', 'value', () => {
